import Link from 'next/link';
import { notFound } from 'next/navigation';
import type { Metadata } from 'next';

interface Post {
  id: number;
  title: string;
  body: string;
}

interface Comment {
  id: number;
  name: string;
  body: string;
  email: string;
}

interface PageProps {
  params: Promise<{ id: string }>;
}

export async function generateStaticParams() {
  const res = await fetch('https://jsonplaceholder.typicode.com/posts');
  const posts: Post[] = await res.json();

  return posts.slice(0, 10).map((post) => ({
    id: post.id.toString(),
  }));
}

export async function generateMetadata({
  params,
}: PageProps): Promise<Metadata> {
  const { id } = await params;
  const res = await fetch(
    `https://jsonplaceholder.typicode.com/posts/${id}`,
  );
  if (!res.ok) return { title: 'Post Not Found' };

  const post: Post = await res.json();

  return {
    title: post.title,
    description: post.body.substring(0, 160),
    openGraph: {
      title: post.title,
      description: post.body.substring(0, 160),
    },
  };
}

// Equivalent to fallback: 'blocking' — generate on-demand at request time
export const dynamicParams = true;
export const revalidate = 300;

export default async function BlogPost({ params }: PageProps) {
  const { id } = await params;

  try {
    const [postRes, commentsRes] = await Promise.all([
      fetch(`https://jsonplaceholder.typicode.com/posts/${id}`),
      fetch(`https://jsonplaceholder.typicode.com/posts/${id}/comments`),
    ]);

    if (!postRes.ok) {
      notFound();
    }

    const post: Post = await postRes.json();
    const comments: Comment[] = await commentsRes.json();

    return (
      <article>
        <Link href="/blog">&larr; Back</Link>

        <h1>{post.title}</h1>
        <p>{post.body}</p>

        <h2>Comments ({comments.length})</h2>
        <div className="comments">
          {comments.map((comment) => (
            <div key={comment.id} className="comment">
              <h3>{comment.name}</h3>
              <p>{comment.body}</p>
              <small>By: {comment.email}</small>
            </div>
          ))}
        </div>
      </article>
    );
  } catch {
    notFound();
  }
}

